arguments.new_str:
using Microsoft.ML;
using ChurnPredictor.Models;

var builder = WebApplication.CreateBuilder(args);
var app = builder.Build();

var mlContext = new MLContext(seed: 0);
var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "customers.csv");

// Load data
var rawData = mlContext.Data.LoadFromTextFile<CustomerData>(
    dataPath, hasHeader: true, separatorChar: ',');

// Build pipeline: map "Yes"/"No" to boolean label, encode Region, train
var pipeline = mlContext.Transforms.CustomMapping<CustomerData, ChurnLabel>(
        (input, output) => output.Label = input.Churned == "Yes",
        contractName: "ChurnMapping")
    .Append(mlContext.Transforms.Categorical.OneHotEncoding("RegionEncoded", nameof(CustomerData.Region)))
    .Append(mlContext.Transforms.Concatenate("Features",
        nameof(CustomerData.Age),
        nameof(CustomerData.Income),
        nameof(CustomerData.PurchaseHistory),
        "RegionEncoded"))
    .Append(mlContext.Transforms.NormalizeMinMax("Features"))
    .Append(mlContext.BinaryClassification.Trainers.SdcaLogisticRegression(
        labelColumnName: "Label", featureColumnName: "Features"));

var model = pipeline.Fit(rawData);
var predictionEngine = mlContext.Model.CreatePredictionEngine<CustomerData, ChurnPrediction>(model);

Console.WriteLine("Model trained successfully.");

// Predict endpoint
app.MapPost("/predict", (CustomerRequest req) =>
{
    var input = new CustomerData
    {
        Age = req.Age,
        Income = req.Income,
        Region = req.Region,
        PurchaseHistory = req.PurchaseHistory
    };

    var prediction = predictionEngine.Predict(input);

    return Results.Ok(new
    {
        Churned = prediction.PredictedLabel ? "Yes" : "No",
        prediction.Probability,
        prediction.Score
    });
});

app.MapGet("/", () => "ChurnPredictor API is running. POST to /predict with { age, income, region, purchaseHistory }.");

app.Run();

// Helper class for the custom label mapping
public class ChurnLabel
{
    public bool Label { get; set; }
}

// Request DTO
public record CustomerRequest(float Age, float Income, string Region, float PurchaseHistory);

